arguments.new_str:
using Microsoft.ML;
using Microsoft.ML.AutoML;
using Microsoft.ML.Data;
using Microsoft.Extensions.ML;

var builder = WebApplication.CreateBuilder(args);

// --- Train model at startup and save to disk ---
var mlContext = new MLContext(seed: 42);
var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "customers.csv");
var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "model.zip");

IDataView data = mlContext.Data.LoadFromTextFile<ChurnInput>(dataPath, hasHeader: true, separatorChar: ',');
var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(ChurnInput.Region))
    .Append(mlContext.Transforms.Concatenate("Features",
        nameof(ChurnInput.Age), nameof(ChurnInput.Income), "RegionEncoded", nameof(ChurnInput.PurchaseHistory)))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.Auto().BinaryClassification(labelColumnName: nameof(ChurnInput.Churned)));

var experiment = mlContext.Auto().CreateExperiment()
    .SetPipeline(pipeline)
    .SetBinaryClassificationMetric(BinaryClassificationMetric.AreaUnderRocCurve)
    .SetTrainingTimeInSeconds(30)
    .SetDataset(split.TrainSet, split.TestSet);

var result = await experiment.RunAsync();
var metrics = result.Metric;
Console.WriteLine($"Best model AUC: {metrics:F4}");

mlContext.Model.Save(result.Model, split.TrainSet.Schema, modelPath);
Console.WriteLine($"Model saved to {modelPath}");

// Evaluate on test set
var predictions = result.Model.Transform(split.TestSet);
var evalMetrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: nameof(ChurnInput.Churned));
Console.WriteLine($"Accuracy: {evalMetrics.Accuracy:F4}");
Console.WriteLine($"F1 Score: {evalMetrics.F1Score:F4}");
Console.WriteLine($"AUC:      {evalMetrics.AreaUnderRocCurve:F4}");

// --- Register prediction engine pool (thread-safe) ---
builder.Services.AddPredictionEnginePool<ChurnInput, ChurnOutput>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapGet("/", () => "Churn Predictor API — POST /predict with customer JSON");

app.MapPost("/predict", (PredictionEnginePool<ChurnInput, ChurnOutput> pool, ChurnRequest req) =>
{
    var input = new ChurnInput
    {
        Age = req.Age,
        Income = req.Income,
        Region = req.Region,
        PurchaseHistory = req.PurchaseHistory
    };
    var prediction = pool.Predict(input);
    return Results.Ok(new
    {
        WillChurn = prediction.PredictedLabel,
        Probability = prediction.Probability,
        Score = prediction.Score
    });
});

app.Run();

// --- Data models ---

public class ChurnInput
{
    [LoadColumn(0)] public float Age { get; set; }
    [LoadColumn(1)] public float Income { get; set; }
    [LoadColumn(2)] public string Region { get; set; } = string.Empty;
    [LoadColumn(3)] public float PurchaseHistory { get; set; }
    [LoadColumn(4), ColumnName("Label")]
    public bool Churned { get; set; }
}

public class ChurnOutput
{
    [ColumnName("PredictedLabel")] public bool PredictedLabel { get; set; }
    public float Probability { get; set; }
    public float Score { get; set; }
}

public record ChurnRequest(float Age, float Income, string Region, float PurchaseHistory);

