var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "customers.csv");
var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "model.zip");

IDataView rawData = mlContext.Data.LoadFromTextFile<ChurnInput>(dataPath, hasHeader: true, separatorChar: ',');

// Map "Yes"/"No" to bool Label, then split
var labelMap = mlContext.Transforms.Conversion.MapValue("Label",
    new[] {
        new KeyValuePair<ReadOnlyMemory<char>, bool>("Yes".AsMemory(), true),
        new KeyValuePair<ReadOnlyMemory<char>, bool>("No".AsMemory(), false)
    },
    inputColumnName: nameof(ChurnInput.Churned));
IDataView data = labelMap.Fit(rawData).Transform(rawData);
var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

// Feature engineering + trainer pipeline
var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(ChurnInput.Region))
    .Append(mlContext.Transforms.Concatenate("Features",
        nameof(ChurnInput.Age), nameof(ChurnInput.Income), "RegionEncoded", nameof(ChurnInput.PurchaseHistory)))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
        labelColumnName: "Label", featureColumnName: "Features"));

var model = pipeline.Fit(split.TrainSet);

// Evaluate on test set
var predictions = model.Transform(split.TestSet);
var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");
