 using Microsoft.ML;
 using Microsoft.ML.Data;
 using Microsoft.Extensions.ML;

 var builder = WebApplication.CreateBuilder(args);

 // --- Train model at startup and save to disk ---
 var mlContext = new MLContext(seed: 42);
 var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "customers.csv");
 var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "model.zip");

 IDataView rawData = mlContext.Data.LoadFromTextFile<ChurnInput>(dataPath, hasHeader: true, separatorChar: ',');

 // Map "Yes"/"No" to bool Label, then split
 var labelMap = mlContext.Transforms.Conversion.MapValue("Label",
     new[] {
         new KeyValuePair<ReadOnlyMemory<char>, bool>("Yes".AsMemory(), true),
         new KeyValuePair<ReadOnlyMemory<char>, bool>("No".AsMemory(), false)
     },
     inputColumnName: nameof(ChurnInput.Churned));
 IDataView data = labelMap.Fit(rawData).Transform(rawData);
 var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

 // Feature engineering + trainer pipeline
 var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(ChurnInput.Region))
     .Append(mlContext.Transforms.Concatenate("Features",
         nameof(ChurnInput.Age), nameof(ChurnInput.Income), "RegionEncoded", nameof(ChurnInput.PurchaseHistory)))
     .Append(mlContext.Transforms.NormalizeMinMax("Features"))
     .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
         labelColumnName: "Label", featureColumnName: "Features"));

 var model = pipeline.Fit(split.TrainSet);

 // Evaluate on test set (guard against too-small datasets)
 var predictions = model.Transform(split.TestSet);
 var testRows = mlContext.Data.CreateEnumerable<ChurnOutput>(predictions, reuseRowObject: false).ToList();
 var hasPositive = testRows.Any(r => r.PredictedLabel);
 var hasNegative = testRows.Any(r => !r.PredictedLabel);

 if (testRows.Count >= 2 && hasPositive && hasNegative)
 {
     var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");
     Console.WriteLine($"Accuracy: {metrics.Accuracy:F4}");
     Console.WriteLine($"F1 Score: {metrics.F1Score:F4}");
     Console.WriteLine($"AUC:      {metrics.AreaUnderRocCurve:F4}");
 }
 else
 {
     Console.WriteLine($"Test set has {testRows.Count} row(s) — too small for reliable metrics. Add more data.");
 }

 mlContext.Model.Save(model, split.TrainSet.Schema, modelPath);
 Console.WriteLine($"Model saved to {modelPath}");

 // --- Register prediction engine pool (thread-safe) ---
 builder.Services.AddPredictionEnginePool<ChurnInput, ChurnOutput>()
     .FromFile(modelPath);

 var app = builder.Build();

 app.MapGet("/", () => "Churn Predictor API — POST /predict with customer JSON");

 app.MapPost("/predict", (PredictionEnginePool<ChurnInput, ChurnOutput> pool, ChurnRequest req) =>
 {
     var input = new ChurnInput
     {
         Age = req.Age,
         Income = req.Income,
         Region = req.Region,
         PurchaseHistory = req.PurchaseHistory
     };
     var prediction = pool.Predict(input);
     return Results.Ok(new
     {
         WillChurn = prediction.PredictedLabel,
         Probability = prediction.Probability,
         Score = prediction.Score
     });
 });

 app.Run();

 // --- Data models ---

 public class ChurnInput
 {
     [LoadColumn(0)] public float Age { get; set; }
     [LoadColumn(1)] public float Income { get; set; }
     [LoadColumn(2)] public string Region { get; set; } = string.Empty;
     [LoadColumn(3)] public float PurchaseHistory { get; set; }
     [LoadColumn(4)] public string Churned { get; set; } = string.Empty;
 }

 public class ChurnOutput
 {
     [ColumnName("PredictedLabel")] public bool PredictedLabel { get; set; }
     public float Probability { get; set; }
     public float Score { get; set; }
 }

 public record ChurnRequest(float Age, float Income, string Region, float PurchaseHistory);
